/* ---------- bedrooms & units ---------- */
const ROOMS = [
  { id: "baba",     name: "Baba's Room",          short: "Baba's" },
  { id: "upstairs", name: "Upstairs Double Room",  short: "Upstairs Dbl" },
  { id: "pollys",   name: "Polly's Room",          short: "Polly's" },
  { id: "tv",       name: "TV Guest Room",         short: "TV Room" },
  { id: "east",     name: "East Guest Wing",       short: "East Wing" },
  { id: "west",     name: "West Guest Wing",       short: "West Wing" },
  { id: "franklin", name: "Franklin's Cabin",      short: "Franklin's" },
];
// Two bookable units, plus Franklin's Cabin as its own standalone.
const UNITS = [
  { id: "main",     name: "Main House",       roomIds: ["baba", "upstairs", "pollys"] },
  { id: "guest",    name: "Guest Wing",       roomIds: ["tv", "east", "west"] },
  { id: "franklin", name: "Franklin's Cabin", roomIds: ["franklin"], standalone: true },
];
const ALL_ROOM_IDS = ROOMS.map((r) => r.id);
const roomShort = (id) => (ROOMS.find((r) => r.id === id)?.short || id);
// Describe a set of rooms, collapsing any fully-selected multi-room unit into its name.
const describeRooms = (roomIds) => {
  const set = new Set(roomIds || []);
  const parts = [], covered = new Set();
  for (const u of UNITS) {
    if (u.roomIds.length > 1 && u.roomIds.every((rid) => set.has(rid))) {
      parts.push(u.name);
      u.roomIds.forEach((rid) => covered.add(rid));
    }
  }
  for (const rid of roomIds || []) if (!covered.has(rid)) parts.push(roomShort(rid));
  return parts.join(", ") || "no rooms set";
};
// An exclusive stay takes the whole house (every room); a shared stay takes only its selected rooms.
const occupiedRooms = (b) => (b.type === "exclusive" ? ALL_ROOM_IDS : (b.rooms || []));
// A "pending" stay is a soft hold: it shows on the calendar but doesn't block rooms
// or count against allowances until someone confirms it.
const isPending = (b) => b.status === "pending";
const isBlocking = (b) => b.status !== "pending"; // confirmed stays hold their rooms
// Rooms that a candidate booking would double-book against a list of others (same room + overlapping dates).
const roomClashes = (cand, others) => {
  if (isPending(cand)) return []; // a soft hold never hard-blocks
  const mine = new Set(occupiedRooms(cand));
  const clashes = [];
  for (const o of others) {
    if (cand.id != null && o.id === cand.id) continue;
    if (isPending(o)) continue; // holds don't block a real booking
    if (!overlaps(cand.start, cand.end, o.start, o.end)) continue;
    for (const rid of occupiedRooms(o)) if (mine.has(rid)) clashes.push({ room: rid, other: o });
  }
  return clashes;
};

/* ---------- date helpers (local, TZ-safe via y/m/d) ---------- */
const pad = (n) => String(n).padStart(2, "0");
const toISO = (d) => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
const parseISO = (s) => { const [y, m, d] = s.split("-").map(Number); return new Date(y, m - 1, d); };
const addDays = (d, n) => { const x = new Date(d); x.setDate(x.getDate() + n); return x; };
const nights = (a, b) => Math.round((parseISO(b) - parseISO(a)) / 86400000);
const eachNight = (a, b) => {
  const out = []; let cur = parseISO(a); const end = parseISO(b);
  while (cur < end) { out.push(toISO(cur)); cur = addDays(cur, 1); }
  return out;
};
const overlaps = (a1, b1, a2, b2) => parseISO(a1) < parseISO(b2) && parseISO(a2) < parseISO(b1);
// Does a booking cover the night of `iso`? ISO strings compare correctly as strings.
const coversNight = (b, iso) => b.start <= iso && iso < b.end;
const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const prettyRange = (a, b) => {
  const A = parseISO(a), B = parseISO(b);
  const sameMonth = A.getMonth() === B.getMonth() && A.getFullYear() === B.getFullYear();
  const f = (d, withMonth) => `${withMonth ? MONTHS[d.getMonth()].slice(0, 3) + " " : ""}${d.getDate()}`;
  return `${f(A, true)} – ${f(B, !sameMonth)}`;
};
const prettyDate = (iso) => { const d = parseISO(iso); return `${MONTHS[d.getMonth()].slice(0, 3)} ${d.getDate()}, ${d.getFullYear()}`; };
const EXPENSE_CATS = ["Property tax", "Insurance", "Utilities", "Association", "Maintenance", "Repair", "Landscaping", "Supplies", "Improvement", "Capital project", "Reserve contribution", "Other"];
/* Every expense is one of three kinds:
   - reserve : a contribution paid INTO the sinking fund (not a shared cost to split)
   - capital : a big-ticket project drawn FROM the reserve (already funded 50/50, so it
               doesn't enter who-owes-whom)
   - operating : the recurring nut (tax, insurance, utilities, dues, upkeep) — split 50/50 */
const CAPITAL_CATS = new Set(["Capital project", "Improvement"]);
const RESERVE_CATS = new Set(["Reserve contribution"]);
const catKind = (c) => RESERVE_CATS.has(c) ? "reserve" : CAPITAL_CATS.has(c) ? "capital" : "operating";
/* The operating budget rolls the raw categories up into a handful of display buckets. */
const OP_BUCKETS = [
  { key: "tax",   label: "Property tax",         cats: ["Property tax"],                              color: "#3d6b5c", desc: "Town of Dartmouth assessment" },
  { key: "ins",   label: "Insurance",            cats: ["Insurance"],                                 color: "#5b8a7a", desc: "homeowners + flood / wind (coastal)" },
  { key: "maint", label: "Maintenance & repairs", cats: ["Maintenance", "Repair", "Landscaping", "Supplies", "Other"], color: "#7ea895", desc: "grounds, systems, old-house upkeep" },
  { key: "util",  label: "Utilities",            cats: ["Utilities"],                                 color: "#a7c3b6", desc: "electric, heat, water, internet" },
  { key: "assoc", label: "Association",          cats: ["Association"],                                color: "#c8d8ce", desc: "Mishaum Point roads, water & beach" },
];
const bucketFor = (c) => OP_BUCKETS.find((b) => b.cats.includes(c)) || OP_BUCKETS[2];

/* ---------- major (always-shared) weekends ---------- */
const nthMonday = (year, month, first) => {
  // month: 0-based. first=true -> first Monday, else last Monday
  if (first) {
    const d = new Date(year, month, 1);
    while (d.getDay() !== 1) d.setDate(d.getDate() + 1);
    return d;
  }
  const d = new Date(year, month + 1, 0);
  while (d.getDay() !== 1) d.setDate(d.getDate() - 1);
  return d;
};
const majorWeekendSet = (year) => {
  const set = new Map(); // iso -> label
  const mark = (d, label) => set.set(toISO(d), label);
  const mem = nthMonday(year, 4, false); // last Mon of May
  [addDays(mem, -2), addDays(mem, -1), mem].forEach((d) => mark(d, "Memorial Day"));
  [new Date(year, 6, 3), new Date(year, 6, 4), new Date(year, 6, 5)].forEach((d) => mark(d, "July 4th"));
  const lab = nthMonday(year, 8, true); // first Mon of Sep
  [addDays(lab, -2), addDays(lab, -1), lab].forEach((d) => mark(d, "Labor Day"));
  return set;
};

/* ---------- iCal export (honors Apple Calendar preference) ---------- */
const escICS = (s) => String(s).replace(/\\/g, "\\\\").replace(/;/g, "\\;").replace(/,/g, "\\,").replace(/\n/g, "\\n");
const buildICS = (bookings) => {
  const stamp = new Date().toISOString().replace(/[-:]/g, "").split(".")[0] + "Z";
  const L = ["BEGIN:VCALENDAR", "VERSION:2.0", "PRODID:-//Mishaum Point//House Calendar//EN", "CALSCALE:GREGORIAN"];
  bookings.forEach((b) => {
    const fam = FAMILIES[b.family];
    const roomsLabel = b.type === "exclusive" ? "Whole house" : describeRooms(b.rooms);
    const summary = `Mishaum — ${fam.label} (${b.type === "exclusive" ? "exclusive" : "shared"})${isPending(b) ? " · HOLD" : ""}`;
    const whoList = (b.members && b.members.length)
      ? b.members.join(", ") + (b.guests ? ` + ${b.guests} guest${b.guests > 1 ? "s" : ""}` : "")
      : `${b.people || 0} family${b.guests ? ` + ${b.guests} guest${b.guests > 1 ? "s" : ""}` : ""}`;
    const desc = `${roomsLabel} · ${whoList}${b.notes ? ` — ${b.notes}` : ""}`;
    L.push("BEGIN:VEVENT", `UID:${b.id}@mishaum`, `DTSTAMP:${stamp}`,
      `DTSTART;VALUE=DATE:${b.start.replace(/-/g, "")}`,
      `DTEND;VALUE=DATE:${b.end.replace(/-/g, "")}`,
      `SUMMARY:${escICS(summary)}`, `DESCRIPTION:${escICS(desc)}`, "END:VEVENT");
  });
  L.push("END:VCALENDAR");
  return L.join("\r\n");
};
const download = (name, text) => {
  const blob = new Blob([text], { type: "text/calendar;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = name; document.body.appendChild(a); a.click();
  a.remove(); URL.revokeObjectURL(url);
};
const downloadJSON = (name, obj) => {
  const blob = new Blob([JSON.stringify(obj, null, 2)], { type: "application/json;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = name; document.body.appendChild(a); a.click();
  a.remove(); URL.revokeObjectURL(url);
};

